function App() {
  return (
    <div style={{ 
      padding: '20px', 
      fontFamily: 'Arial',
      textAlign: 'center',
      marginTop: '50px'
    }}>
      <h1 style={{ color: 'blue' }}>📚 LibraryManager</h1>
      <p>L'application fonctionne !</p>
      <p><a href="/login" style={{ color: 'blue' }}>Aller à la page de connexion</a></p>
    </div>
  );
}

export default App;
